const q = $input.first().json.query || {};

// Filtros
const filtros = [`_type == 'imovel'`, `finalidade == 'Venda'`, `status == 'Disponível'`];
if (q.bairro) filtros.push(`bairro->slug.current == '${q.bairro}'`);
if (q.tipo) filtros.push(`tipo == '${q.tipo}'`);
if (q.quartos) filtros.push(`quartos >= ${Number(q.quartos)}`);
if (q.precoMin) filtros.push(`preco >= ${Number(q.precoMin)}`);
if (q.precoMax) filtros.push(`preco <= ${Number(q.precoMax)}`);
if (q.destaque === 'true') filtros.push(`destaque == true`);

// Paginação
const por_pagina = Number(q.por_pagina) || 20;
const pagina = Number(q.pagina) || 1;
const offset = (pagina - 1) * por_pagina;

const groq = `*[${filtros.join(' && ')}] | order(destaque desc, _createdAt desc) [${offset}...${offset + por_pagina}] {
  _id, titulo, slug, status, tipo, preco, precoCondominio,
  quartos, suites, banheiros, vagas, areaUtil, areaTotal, destaque,
  'bairro': bairro->{ nome, slug },
  'condominio': condominio->{ nome, slug },
  'fotoCapa': fotoCapa { asset->{ url, metadata { lqip } }, hotspot, crop }
}`;

const groqContagem = `count(*[${filtros.join(' && ')}])`;

return [{ json: { groq: encodeURIComponent(groq), groqContagem: encodeURIComponent(groqContagem), por_pagina, pagina } }];

const imoveis = $('Sanity — Buscar imóveis').item.json.result || [];
const total = $('Sanity — Contar total').item.json.result || 0;
const por_pagina = $('Montar query GROQ').item.json.por_pagina;
const pagina = $('Montar query GROQ').item.json.pagina;

return [{
  json: {
    imoveis,
    paginacao: {
      total,
      pagina,
      por_pagina,
      total_paginas: Math.ceil(total / por_pagina)
    }
  }
}];
